import React from 'react';


function Navbar() {
  return (
    <nav className="navbar">
      <div className="logo">QuickCart</div>
      <ul className="nav-links">
        <li>Home</li>
        <li>Shop</li>
        <li>About Us</li>
        <li>Contact</li>
        <li><button className="dashboard-btn">Seller Dashboard</button></li>
      </ul>
      <div className="nav-icons">
        <span>🔍</span>
        <span>👤</span>
      </div>
    </nav>
  );
}

export default Navbar;
